package ingest

import (
	"os"
	"path/filepath"
	"testing"

	"github.com/a<HOME>/agentic-rag-mcp/internal/config"
)

func defaultSecurityConfig() config.SecurityConfig {
	return config.SecurityConfig{
		ExtensionAllowlist: []string{".md", ".txt"},
		FilenameBlocklist:  []string{".env.md", ".env.txt", "credentials.md"},
		DirectoryBlocklist: []string{"node_modules", ".git", "__pycache__", "vendor"},
		MaxFileSizeBytes:   1 * 1024 * 1024,
	}
}

func TestSecurityFilterExtensionAllowlist(t *testing.T) {
	cfg := defaultSecurityConfig()

	tests := []struct {
		name    string
		path    string
		allowed bool
	}{
		{"md allowed", "docs/architecture.md", true},
		{"txt allowed", "docs/notes.txt", true},
		{"go rejected", "main.go", false},
		{"py rejected", "script.py", false},
		{"no ext rejected", "README", false},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := SecurityFilter(tt.path, nil, cfg)
			if result.Allowed != tt.allowed {
				t.Errorf("SecurityFilter(%q).Allowed = %v, want %v (reason: %s)",
					tt.path, result.Allowed, tt.allowed, result.Reason)
			}
		})
	}
}

func TestSecurityFilterFilenameBlocklist(t *testing.T) {
	cfg := defaultSecurityConfig()

	result := SecurityFilter(".env.md", nil, cfg)
	if result.Allowed {
		t.Error(".env.md should be blocked")
	}

	result = SecurityFilter("credentials.md", nil, cfg)
	if result.Allowed {
		t.Error("credentials.md should be blocked")
	}
}

func TestSecurityFilterDirectoryBlocklist(t *testing.T) {
	cfg := defaultSecurityConfig()

	result := SecurityFilter(filepath.Join("node_modules", "pkg", "doc.md"), nil, cfg)
	if result.Allowed {
		t.Error("node_modules should be blocked")
	}

	result = SecurityFilter(filepath.Join(".git", "hooks", "readme.md"), nil, cfg)
	if result.Allowed {
		t.Error(".git should be blocked")
	}
}

func TestSecurityFilterSizeLimit(t *testing.T) {
	cfg := defaultSecurityConfig()

	dir := t.TempDir()
	bigFile := filepath.Join(dir, "huge.md")
	// Write a file larger than 1MB
	data := make([]byte, 2*1024*1024)
	os.WriteFile(bigFile, data, 0644)

	info, _ := os.Stat(bigFile)
	result := SecurityFilter(bigFile, info, cfg)
	if result.Allowed {
		t.Error("file exceeding size limit should be blocked")
	}

	// Small file should pass
	smallFile := filepath.Join(dir, "small.md")
	os.WriteFile(smallFile, []byte("# Hello"), 0644)
	info, _ = os.Stat(smallFile)
	result = SecurityFilter(smallFile, info, cfg)
	if !result.Allowed {
		t.Errorf("small file should be allowed: %s", result.Reason)
	}
}
